import React, { useState, useEffect, useCallback } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { useSubscription } from '../../contexts/SubscriptionContext';
import { useAuth } from '../../hooks/useAuth';

const PaymentSuccessPage = () => {
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [checkingSubscription, setCheckingSubscription] = useState(false);
  const [subscriptionTier, setSubscriptionTier] = useState(null);
  const [timeoutMessage, setTimeoutMessage] = useState(false);
  const [manualCheckCount, setManualCheckCount] = useState(0);
  
  const location = useLocation();
  const navigate = useNavigate();
  const { refreshSubscription, subscription, formatTierName } = useSubscription();
  const { isAuthenticated, loading: authLoading } = useAuth();
  
  // Extract the session ID from URL query parameters
  const getSessionId = useCallback(() => {
    const searchParams = new URLSearchParams(location.search);
    return searchParams.get('session_id');
  }, [location.search]);
  
  // Function to manually check subscription status
  const checkSubscriptionNow = async () => {
    setManualCheckCount(prev => prev + 1);
    try {
      setTimeoutMessage(false);
      const data = await refreshSubscription();
      console.log('Manual subscription check result:', data);
      
      if (data && data.tier) {
        console.log(`Manual check successful, tier: ${data.tier}`);
        setSubscriptionTier(data.tier);
        setLoading(false);
        setCheckingSubscription(false);
        return true;
      }
      return false;
    } catch (err) {
      console.error('Error in manual subscription check:', err);
      return false;
    }
  };
  
  // Handle direct session checking (for backup)
  const checkSessionStatus = useCallback(async (sessionId) => {
    if (!sessionId) return;
    
    try {
      console.log(`Directly checking session status for ID: ${sessionId}`);
      
      // Note: You need to implement this endpoint on your server
      const response = await fetch(`/api/stripe/check-session/${sessionId}`, {
        headers: {
          'Authorization': `Bearer ${localStorage.getItem('token')}`
        }
      });
      
      if (!response.ok) {
        console.log('Session check endpoint not implemented or returned error');
        return;
      }
      
      const data = await response.json();
      
      if (data.success && data.session && data.session.payment_status === 'paid') {
        console.log('Session confirmed paid via direct check');
        const tier = data.session.metadata?.tier || 'premium';
        setSubscriptionTier(tier);
        setLoading(false);
        setCheckingSubscription(false);
      }
    } catch (err) {
      console.error('Error checking session directly:', err);
      // Just log the error, don't interrupt the flow
    }
  }, []);
  
  // Force payment to be considered successful
  const forceSuccess = (tier) => {
    console.log(`Forcing success with tier: ${tier}`);
    setSubscriptionTier(tier);
    setLoading(false);
    setCheckingSubscription(false);
  };
  
  useEffect(() => {
    console.log('PaymentSuccessPage mounted');
    console.log('Auth state:', { isAuthenticated, authLoading });
    console.log('Current subscription:', subscription);
    
    // Force completion after maximum time to avoid infinite spinner
    const forceTimeout = setTimeout(() => {
      console.log('Force timeout reached - showing timeout message');
      setTimeoutMessage(true);
      // Keep spinner to allow manual actions instead of forcing end
    }, 20000); // 20 seconds maximum wait
    
    const checkSubscriptionStatus = async () => {
      try {
        // Wait for authentication to complete before proceeding
        if (authLoading) {
          console.log("Auth is still loading, waiting...");
          return; // Exit early and wait for next effect run when auth completes
        }
        
        // If not authenticated, redirect to login with return URL
        if (!isAuthenticated) {
          console.log("Not authenticated, redirecting to login...");
          const currentPath = location.pathname + location.search;
          navigate(`/login?redirect=${encodeURIComponent(currentPath)}`);
          return;
        }
        
        console.log("User is authenticated, checking subscription...");
        setLoading(true);
        setCheckingSubscription(true);
        
        const sessionId = getSessionId();
        console.log('Session ID from URL:', sessionId);
        
        // Try direct session check if available
        if (sessionId) {
          checkSessionStatus(sessionId).catch(err => {
            console.error('Error in session check:', err);
          });
        }
        
        // First refresh to get current state
        const initialData = await refreshSubscription();
        console.log('Initial subscription data:', initialData);
        
        // If subscription is already non-basic, we're good
        if (initialData && initialData.tier && initialData.tier !== 'basic') {
          console.log(`Already subscribed to ${initialData.tier}, no need to poll`);
          setSubscriptionTier(initialData.tier);
          setLoading(false);
          setCheckingSubscription(false);
          clearTimeout(forceTimeout);
          return;
        }
        
        // Otherwise poll for updates for a short time
        console.log('Starting subscription polling...');
        let attempts = 0;
        const maxAttempts = 8; // Try for about 24 seconds
        
        const checkInterval = setInterval(async () => {
          attempts++;
          console.log(`Refreshing subscription data (attempt ${attempts}/${maxAttempts})...`);
          
          try {
            const refreshedData = await refreshSubscription();
            console.log('Refreshed subscription data:', refreshedData);
            
            // If we have a non-basic subscription or any paid tier, we're done
            if (refreshedData && refreshedData.tier && 
                (refreshedData.tier !== 'basic' || refreshedData.hasSubscription)) {
              console.log(`Subscription updated to ${refreshedData.tier}`);
              setSubscriptionTier(refreshedData.tier);
              clearInterval(checkInterval);
              clearTimeout(forceTimeout);
              setLoading(false);
              setCheckingSubscription(false);
            }
          } catch (refreshError) {
            console.error('Error refreshing subscription:', refreshError);
          }
          
          // If we reached max attempts, just show timeout message but keep spinner
          if (attempts >= maxAttempts) {
            console.log('Max attempts reached, stopping polling');
            clearInterval(checkInterval);
            setTimeoutMessage(true);
            // Keep loading state active to show manual options
          }
        }, 3000); // Check every 3 seconds
        
        // Cleanup interval on component unmount
        return () => {
          console.log('Clearing subscription check interval');
          clearInterval(checkInterval);
          clearTimeout(forceTimeout);
        };
      } catch (err) {
        console.error('Error checking subscription status:', err);
        setError('Failed to verify subscription status. Please contact support.');
        setLoading(false);
        setCheckingSubscription(false);
        clearTimeout(forceTimeout);
      }
    };
    
    checkSubscriptionStatus();
  }, [isAuthenticated, authLoading, navigate, refreshSubscription, location, getSessionId, checkSessionStatus, subscription]);
  
  // Also refresh when subscription changes
  useEffect(() => {
    if (subscription && subscription.tier && subscription.tier !== 'basic' && !subscriptionTier) {
      console.log(`Subscription detected: ${subscription.tier}`);
      setSubscriptionTier(subscription.tier);
      setLoading(false);
      setCheckingSubscription(false);
    }
  }, [subscription, subscriptionTier]);
  
  // Show loading screen while checking authentication
  if (loading && authLoading) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-gray-50 px-4">
        <div className="max-w-md w-full bg-white rounded-lg shadow-md p-8 text-center">
          <h2 className="text-2xl font-bold text-gray-900 mb-4">Checking Authentication</h2>
          <p className="text-gray-600 mb-6">
            Please wait while we verify your account...
          </p>
          <div className="flex justify-center">
            <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-indigo-500"></div>
          </div>
        </div>
      </div>
    );
  }
  
  // Show loading screen while checking subscription status
  if (loading && checkingSubscription) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-gray-50 px-4">
        <div className="max-w-md w-full bg-white rounded-lg shadow-md p-8 text-center">
          <h2 className="text-2xl font-bold text-gray-900 mb-4">Processing Your Subscription</h2>
          <p className="text-gray-600 mb-6">
            Please wait while we confirm your subscription...
          </p>
          <div className="flex justify-center mb-6">
            <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-indigo-500"></div>
          </div>
          
          {timeoutMessage && (
            <div className="mt-4 p-4 bg-yellow-50 text-sm rounded-md">
              <p className="text-amber-700 font-medium">This is taking longer than expected.</p>
              <p className="text-gray-600 mt-1">
                Your payment was likely successful, but our system is still processing it.
                You can try manually checking your subscription status, continue to the dashboard, 
                or wait a bit longer.
              </p>
              
              <div className="flex flex-wrap justify-center gap-3 mt-4">
                <button
                  onClick={checkSubscriptionNow}
                  disabled={manualCheckCount > 5}
                  className="px-4 py-2 border border-indigo-300 bg-indigo-50 text-indigo-700 rounded hover:bg-indigo-100 disabled:opacity-50"
                >
                  {manualCheckCount > 5 ? 'Check Limit Reached' : 'Check Again'}
                </button>
                
                <Link
                  to="/dashboard"
                  className="px-4 py-2 bg-indigo-600 text-white rounded hover:bg-indigo-700"
                >
                  Go to Dashboard
                </Link>
              </div>
            </div>
          )}
          
          {/* Development Tools - only show in development */}
          {process.env.NODE_ENV !== 'production' && (
            <div className="mt-6 p-3 bg-gray-800 text-white text-sm rounded-md">
              <p className="font-medium">Developer Tools:</p>
              <div className="flex flex-wrap justify-center gap-2 mt-2">
                <button
                  onClick={() => forceSuccess('premium')}
                  className="px-3 py-1 bg-purple-600 text-white text-xs rounded"
                >
                  Force Premium (Dev)
                </button>
                <button
                  onClick={() => forceSuccess('elite')}
                  className="px-3 py-1 bg-purple-800 text-white text-xs rounded"
                >
                  Force Elite (Dev)
                </button>
                <button
                  onClick={() => {
                    setLoading(false);
                    setCheckingSubscription(false);
                  }}
                  className="px-3 py-1 bg-gray-600 text-white text-xs rounded"
                >
                  Skip Loading (Dev)
                </button>
              </div>
            </div>
          )}
        </div>
      </div>
    );
  }
  
  // Show error message if something went wrong
  if (error) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-gray-50 px-4">
        <div className="max-w-md w-full bg-white rounded-lg shadow-md p-8">
          <div className="rounded-full h-16 w-16 flex items-center justify-center bg-red-100 mx-auto">
            <svg className="h-8 w-8 text-red-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </div>
          <h2 className="text-2xl font-bold text-center text-gray-900 mt-4">Something Went Wrong</h2>
          <p className="text-gray-600 text-center mt-2">{error}</p>
          <div className="mt-6 flex justify-center">
            <Link
              to="/subscription/plans"
              className="inline-flex items-center px-4 py-2 border border-transparent rounded-md shadow-sm text-sm font-medium text-white bg-indigo-600 hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500"
            >
              Try Again
            </Link>
          </div>
          
          {/* Development options */}
          {process.env.NODE_ENV !== 'production' && (
            <div className="mt-6 flex justify-center">
              <button
                onClick={() => {
                  // For dev only - continue despite error
                  setError(null);
                  forceSuccess('premium');
                }}
                className="text-xs text-gray-500 underline"
              >
                Continue Anyway (Dev)
              </button>
            </div>
          )}
        </div>
      </div>
    );
  }
  
  // If no subscription was detected after all the checks
  if (!subscriptionTier && !subscription?.tier) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-gray-50 px-4">
        <div className="max-w-md w-full bg-white rounded-lg shadow-md p-8">
          <div className="rounded-full h-16 w-16 flex items-center justify-center bg-yellow-100 mx-auto">
            <svg className="h-8 w-8 text-yellow-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
            </svg>
          </div>
         
          <h2 className="text-2xl font-bold text-center text-gray-900 mt-4">Subscription Pending</h2>
          <p className="text-gray-600 text-center mt-2">
            Your payment was successful, but the subscription update is still processing. 
            This usually takes just a few moments.
          </p>
          <div className="mt-6 flex flex-col space-y-4 sm:flex-row sm:space-y-0 sm:space-x-4 justify-center">
            <Link
              to="/dashboard"
              className="inline-flex justify-center px-4 py-2 border border-transparent rounded-md shadow-sm text-sm font-medium text-white bg-indigo-600 hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500"
            >
              Go to Dashboard
            </Link>
            <button
              onClick={checkSubscriptionNow}
              className="inline-flex justify-center px-4 py-2 border border-gray-300 shadow-sm text-sm font-medium rounded-md text-gray-700 bg-white hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500"
            >
              Check Subscription Status
            </button>
      
  
          </div>
          // In the PaymentSuccessPage.js file, find the part where you have the dashboard and manage subscription buttons
// Add this button right after them
<button
  onClick={() => {
    fetch('/api/stripe/manual-subscription-update', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${localStorage.getItem('token')}`
      },
      body: JSON.stringify({ tier: 'premium' })
    })
    .then(res => res.json())
    .then(data => {
      if (data.success) {
        // Refresh the page to see updated subscription
        window.location.href = '/dashboard';
      }
    });
  }}
  className="inline-flex items-center px-4 py-2 border border-yellow-300 shadow-sm text-sm font-medium rounded-md text-yellow-700 bg-yellow-50 hover:bg-yellow-100 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-yellow-500"
>
  Force Update Subscription
</button>
          
          {/* Development Tools */}
          {process.env.NODE_ENV !== 'production' && (
            <div className="mt-6 p-3 bg-gray-100 text-sm rounded-md">
              <p className="font-medium text-gray-700">Developer Tools:</p>
              <div className="flex flex-wrap justify-center gap-2 mt-2">
                <button
                  onClick={() => forceSuccess('premium')}
                  className="px-3 py-1 bg-purple-600 text-white text-xs rounded"
                >
                  Set Premium (Dev)
                </button>
                <button
                  onClick={() => forceSuccess('elite')}
                  className="px-3 py-1 bg-purple-800 text-white text-xs rounded"
                >
                  Set Elite (Dev)
                </button>
              </div>
            </div>
          )}
        </div>
      </div>
    );
  }
  
  // Success state - subscription confirmed
  return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-gray-50 px-4">
      <div className="max-w-md w-full bg-white rounded-lg shadow-md p-8">
        <div className="rounded-full h-16 w-16 flex items-center justify-center bg-green-100 mx-auto">
          <svg className="h-8 w-8 text-green-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
          </svg>
        </div>
        <h2 className="text-2xl font-bold text-center text-gray-900 mt-4">Payment Successful!</h2>
        <p className="text-gray-600 text-center mt-2">
          Thank you for subscribing to ElderFit Secrets
          {(subscriptionTier || subscription?.tier) ? ` ${formatTierName(subscriptionTier || subscription?.tier)}` : ''}!
        </p>
        <div className="mt-6 space-y-4">
          <div className="bg-gray-50 px-4 py-3 rounded-md">
            <p className="text-sm font-medium text-gray-700">Your subscription is now active.</p>
            <p className="text-sm text-gray-500">
              You now have access to all {subscriptionTier || subscription?.tier || 'premium'} features.
            </p>
          </div>
          
          {subscription && (
            <div className="bg-gray-50 px-4 py-3 rounded-md">
              <h3 className="text-sm font-medium text-gray-700">Subscription Details</h3>
              <p className="text-sm text-gray-500 mt-1">
                Plan: {formatTierName(subscription.tier)}
              </p>
              <p className="text-sm text-gray-500">
                Status: {subscription.status === 'active' ? 'Active' : subscription.status}
              </p>
              {subscription.currentPeriodEnd && (
                <p className="text-sm text-gray-500">
                  Next billing date: {new Date(subscription.currentPeriodEnd).toLocaleDateString()}
                </p>
              )}
            </div>
          )}
        </div>
        
        <div className="mt-6 flex justify-center space-x-4">
          <Link
            to="/dashboard"
            className="inline-flex items-center px-4 py-2 border border-transparent rounded-md shadow-sm text-sm font-medium text-white bg-indigo-600 hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500"
          >
            Go to Dashboard
          </Link>
          <Link
            to="/subscription/manage"
            className="inline-flex items-center px-4 py-2 border border-gray-300 shadow-sm text-sm font-medium rounded-md text-gray-700 bg-white hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500"
          >
            Manage Subscription
          </Link>
        </div>
      </div>
    </div>
  );
};

export default PaymentSuccessPage;
